// Supprimer complètement un article
function removeFromCart(index) {
  if (confirm("Voulez-vous vraiment supprimer cet article ?")) {
    cart.splice(index, 1);
    updateCartCount();
    renderCartPage();
    showNotif("Article supprimé ❌"); // ✅ notification
  }
}

// Diminuer la quantité
function decreaseQuantity(index) {
  if (cart[index].quantity > 1) {
    cart[index].quantity--;
    showNotif("Quantité diminuée ➖"); // ✅ notification
  } else {
    if (confirm("Il ne reste qu'un exemplaire. Voulez-vous le supprimer ?")) {
      cart.splice(index, 1);
      showNotif("Article supprimé ❌"); // ✅ notification
    }
  }
  updateCartCount();
  renderCartPage();
}

// Vider le panier
function clearCart() {
  if (confirm("Voulez-vous vraiment vider tout le panier ?")) {
    cart = [];
    updateCartCount();
    renderCartPage();
    showNotif("Panier vidé 🗑️");
  }
}


// Charger au démarrage
function loadCart() {
  const saved = localStorage.getItem("cart");
  if (saved) {
    cart = JSON.parse(saved);
    updateCartCount();
    renderCartPage();
  }
}

